#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        if (K >= N + 1) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

